import { useLocation, useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import Board from "./Board";
import "./Screens.css";

function SecondScreen() {
    const location = useLocation();
    const navigate = useNavigate();
    const nickname = location.state?.nickname;

    const [moves, setMoves] = useState([]);
    const [winner, setWinner] = useState("");
    const [gameOver, setGameOver] = useState(false);

    useEffect(() => {
        fetch("/moves.json") // Replace with the correct path or URL
            .then((response) => response.json())
            .then((data) => {
                setMoves(data);
                if (data.length > 0) {
                    setWinner(data.length % 2 === 0 ? "X" : "O");
                }
            })
            .catch((error) => console.error("Error fetching moves:", error));
    }, []);

    const handleGameOver = () => {
        setGameOver(true);
    };

    // If no nickname is provided, redirect back to welcome screen
    if (!nickname) {
        navigate("/");
        return null;
    };

    return (
        <div>
            {/* {!isFormSubmitted ? (
              <FirstScreen onFormSubmit={handleFormSubmit} />
          ) : ( */}
            <>
                <Board moves={moves} onGameOver={handleGameOver} />
                {gameOver && (
                    <p
                        style={{
                            textAlign: "center",
                            fontFamily: "monospace",
                        }}
                    >
                        Winner: {winner}
                    </p>
                )}
            </>
        </div>
    );
}

export default SecondScreen;
